(function() {
  'use strict';

  var BLOCKED_EVENTS = [
    'copy', 'cut', 'paste',
    'contextmenu',
    'selectstart', 'select',
    'dragstart', 'drag',
    'mousedown', 'mouseup'
  ];

  // Override addEventListener so blocked-event handlers cannot call preventDefault.
  var origAdd = EventTarget.prototype.addEventListener;
  EventTarget.prototype.addEventListener = function(type, listener, options) {
    if (BLOCKED_EVENTS.indexOf(type) !== -1 && typeof listener === 'function') {
      var wrapped = function(e) {
        var origPrevent = e.preventDefault;
        e.preventDefault = function() {};
        try { listener.call(this, e); } catch (_) {}
        e.preventDefault = origPrevent;
      };
      return origAdd.call(this, type, wrapped, options);
    }
    return origAdd.call(this, type, listener, options);
  };

  function removeInlineHandlers(root) {
    if (!root) return;
    var attrs = [
      'oncopy', 'oncut', 'onpaste',
      'oncontextmenu',
      'onselectstart', 'onselect',
      'ondragstart', 'ondrag',
      'onmousedown', 'onmouseup'
    ];
    if (root.querySelectorAll) {
      root.querySelectorAll('*').forEach(function(el) {
        attrs.forEach(function(attr) {
          if (el.hasAttribute(attr)) el.removeAttribute(attr);
        });
      });
    }
    attrs.forEach(function(attr) {
      if (root.hasAttribute && root.hasAttribute(attr)) root.removeAttribute(attr);
    });
  }

  // Remove document-level handlers.
  BLOCKED_EVENTS.forEach(function(evt) {
    try { document['on' + evt] = null; } catch (_) {}
  });

  // Re-enable selection/copy/right-click by stopping the blockers' propagation.
  document.addEventListener('selectstart', function(e) { e.stopPropagation(); }, true);
  document.addEventListener('contextmenu', function(e) { e.stopPropagation(); }, true);
  document.addEventListener('copy', function(e) { e.stopPropagation(); }, true);
  document.addEventListener('cut', function(e) { e.stopPropagation(); }, true);
  document.addEventListener('paste', function(e) { e.stopPropagation(); }, true);
  document.addEventListener('dragstart', function(e) { e.stopPropagation(); }, true);

  var observer = new MutationObserver(function(mutations) {
    mutations.forEach(function(m) {
      m.addedNodes.forEach(function(node) {
        if (node.nodeType === 1) removeInlineHandlers(node);
      });
    });
  });

  // Injected at document_start, where document.body may not exist yet.
  function start() {
    removeInlineHandlers(document.documentElement);
    removeInlineHandlers(document.body);
    if (document.body) observer.observe(document.body, { childList: true, subtree: true });
  }
  if (document.body) {
    start();
  } else {
    document.addEventListener('DOMContentLoaded', start);
  }

  console.log('[Remove Web Limits] Script active — copy, paste, select, and right-click restored.');
})();

